#include <bits/stdc++.h>
using namespace std;

const int N=5e4+4;

struct Node{
	int l,r,id;
}seg[N];

int n,m,len,c[N],sum[N],ans,num[N],cnt[N];

int cal(int x){
	return (x-1)/len+1;
}

bool cmp(Node x,Node y){
	if(cal(x.l)==cal(y.l))
		return x.r<y.r;
	return cal(x.l)<cal(y.l);
}

int main(){
	scanf("%d%d",&n,&m);
	len=sqrt(n);
	for(int i=1;i<=n;i++)
		scanf("%d",&c[i]);
	for(int i=1;i<=m;i++){
		scanf("%d%d",&seg[i].l,&seg[i].r);
		seg[i].id=i;
	}
	sort(seg+1,seg+m+1,cmp);
	int l=seg[1].l,r=l-1;
	while(r<seg[1].r)
		ans+=sum[c[++r]]++;
	num[seg[1].id]=ans,cnt[seg[1].id]=1LL*(r-l+1)*(r-l)/2;
	for(int i=1;i<=m;i++){
		while(l>seg[i].l)
			ans+=sum[c[--l]]++;
		while(l<seg[i].l)
			ans-=--sum[c[l++]];
		while(r>seg[i].r)
			ans-=--sum[c[r--]];
		while(r<seg[i].r)
			ans+=sum[c[++r]]++;
		num[seg[i].id]=ans,cnt[seg[i].id]=1LL*(r-l+1)*(r-l)/2;
	} 
	for(int i=1;i<=m;i++){
		if(!num[i])
			puts("0/1");
		else
			printf("%d/%d\n",num[i]/__gcd(num[i],cnt[i]),cnt[i]/__gcd(num[i],cnt[i]));
	}
	return 0;
}
